  1	import { ActionGroup, Alert, Button, Flex, FlexItem, Radio } from '@patternfly/react-core';
  2	import React, { FC } from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { ContextSingleton } from '../../utils/context';
  5	import './forms.css';
  6	
  7	export enum EditorType {
  8	  CUSTOM = 'custom',
  9	  YAML = 'yaml'
 10	}
 11	
 12	type EditorToggleProps = {
 13	  type: EditorType;
 14	  onChange: (newValue: EditorType) => void;
 15	  onSubmit: () => void;
 16	  onCancel: () => void;
 17	  onDelete: () => void;
 18	  customChild: JSX.Element;
 19	  yamlChild: JSX.Element;
 20	  updated: boolean;
 21	  isUpdate: boolean;
 22	  onReload: () => void;
 23	};
 24	
 25	export const EditorToggle: FC<EditorToggleProps> = ({
 26	  type,
 27	  onChange,
 28	  onSubmit,
 29	  onCancel,
 30	  onReload,
 31	  onDelete,
 32	  customChild,
 33	  yamlChild,
 34	  updated,
 35	  isUpdate
 36	}) => {
 37	  const { t } = useTranslation('plugin__netobserv-plugin');
 38	
 39	  return (
 40	    <Flex
 41	      className="editor-toggle-container"
 42	      flex={{ default: 'flex_1' }}
 43	      direction={{ default: 'column' }}
 44	      flexWrap={{ default: 'nowrap' }}
 45	    >
 46	      <FlexItem flex={{ default: 'flexNone' }}>
 47	        <Flex
 48	          className="editor-toggle"
 49	          alignItems={{ default: 'alignItemsCenter' }}
 50	          aria-labelledby="radio-group-title-editor-toggle"
 51	          role="radiogroup"
 52	          spaceItems={{ default: 'spaceItemsMd' }}
 53	        >
 54	          <label className="editor-toggle-label" id="radio-group-title-editor-toggle">
 55	            {t('Configure via:')}
 56	          </label>
 57	          <Radio
 58	            data-test={`${EditorType.CUSTOM}-view-input`}
 59	            id={EditorType.CUSTOM}
 60	            isChecked={type === EditorType.CUSTOM}
 61	            label={t('Form view')}
 62	            name={EditorType.CUSTOM}
 63	            onChange={(event, checked) => checked && onChange(EditorType.CUSTOM)}
 64	            value={EditorType.CUSTOM}
 65	          />
 66	          <Radio
 67	            data-test={`${EditorType.YAML}-view-input`}
 68	            id={EditorType.YAML}
 69	            isChecked={type === EditorType.YAML}
 70	            label={t('YAML view')}
 71	            name={EditorType.YAML}
 72	            onChange={(event, checked) => checked && onChange(EditorType.YAML)}
 73	            value={EditorType.YAML}
 74	          />
 75	        </Flex>
 76	      </FlexItem>
 77	      <FlexItem id="editor-content-container" flex={{ default: 'flex_1' }}>
 78	        {type === EditorType.CUSTOM ? customChild : yamlChild}
 79	      </FlexItem>
 80	      {(type === EditorType.CUSTOM || ContextSingleton.isStandalone()) && (
 81	        <FlexItem id="editor-toggle-footer" style={{ paddingBottom: '30px' }}>
 82	          {updated && (
 83	            <Alert isInline className="co-alert" variant="info" title={t('This object has been updated.')}>
 84	              {t('Click reload to see the new version.')}
 85	            </Alert>
 86	          )}
 87	          <ActionGroup className="pf-v6-c-form">
 88	            <Button
 89	              id={isUpdate ? 'update-resource-button' : 'create-resource-button'}
 90	              data-test-id={isUpdate ? 'update-resource-button' : 'create-resource-button'}
 91	              type="submit"
 92	              onClick={onSubmit}
 93	              variant="primary"
 94	            >
 95	              {isUpdate ? t('Update') : t('Create')}
 96	            </Button>
 97	            {updated && (
 98	              <Button
 99	                id="reload-resource-button"
100	                data-test-id="reload-resource-button"
101	                type="submit"
102	                onClick={onReload}
103	                variant="secondary"
104	              >
105	                {t('Reload')}
106	              </Button>
107	            )}
108	            <Button
109	              id="cancel-resource-button"
110	              data-test-id="cancel-resource-button"
111	              onClick={onCancel}
112	              variant="secondary"
113	            >
114	              {t('Cancel')}
115	            </Button>
116	            {isUpdate && (
117	              <Button
118	                id="delete-resource-button"
119	                data-test-id="delete-resource-button"
120	                type="submit"
121	                onClick={onDelete}
122	                variant="danger"
123	              >
124	                {t('Delete')}
125	              </Button>
126	            )}
127	          </ActionGroup>
128	        </FlexItem>
129	      )}
130	    </Flex>
131	  );
132	};

